import{_ as e,o as i,c as t,ak as s}from"./chunks/framework.Chu_0La1.js";const k=JSON.parse('{"title":"📊 用户数据管理","description":"","frontmatter":{"outline":[2,3]},"headers":[],"relativePath":"help/sakura/user-data.md","filePath":"doc/help/sakura/user-data.md"}'),l={name:"help/sakura/user-data.md"};function d(r,a,o,h,n,c){return i(),t("div",null,[...a[0]||(a[0]=[s('<h1 id="📊-用户数据管理" tabindex="-1">📊 用户数据管理 <a class="header-anchor" href="#📊-用户数据管理" aria-label="Permalink to “📊 用户数据管理”">​</a></h1><div class="feature-hero" style="background:linear-gradient(135deg, #a8edea 0%, #fed6e3 100%);"><span class="feature-icon">📊</span><h2 style="color:#2d3748;">用户数据管理</h2><p style="color:#4a5568;">绑定游戏账号、管理查询权限、查看基础信息</p></div><div class="important custom-block github-alert"><p class="custom-block-title">指令前缀</p><p>SakuraBOT 指令<strong>不需要</strong> <code>@mzkbot</code> 前缀，直接发送即可。</p></div><hr><h2 id="基础指令" tabindex="-1">基础指令 <a class="header-anchor" href="#基础指令" aria-label="Permalink to “基础指令”">​</a></h2><div class="command-section"><h3 id="绑定游戏账号" tabindex="-1">绑定游戏账号 <a class="header-anchor" href="#绑定游戏账号" aria-label="Permalink to “绑定游戏账号”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>绑定 ID</span></span></code></pre></div><p>绑定你的 PJSK 游戏账号 ID。</p><blockquote><p>ID 可在游戏个人信息页查看</p></blockquote><h3 id="设置查询权限" tabindex="-1">设置查询权限 <a class="header-anchor" href="#设置查询权限" aria-label="Permalink to “设置查询权限”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>给看</span></span></code></pre></div><p>开放他人 <code>@</code> 查询你的权限。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>不给看</span></span></code></pre></div><p>关闭他人 <code>@</code> 查询你的权限（默认）。</p><h3 id="查看个人资料" tabindex="-1">查看个人资料 <a class="header-anchor" href="#查看个人资料" aria-label="Permalink to “查看个人资料”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>pjskprofile</span></span></code></pre></div><p>获取个人基本信息卡片，类似旧版 Profile。</p><h3 id="查看当前绑定" tabindex="-1">查看当前绑定 <a class="header-anchor" href="#查看当前绑定" aria-label="Permalink to “查看当前绑定”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>id</span></span></code></pre></div><p>查看当前 QQ 绑定的游戏 ID。</p></div><hr><h2 id="社交查询" tabindex="-1">社交查询 <a class="header-anchor" href="#社交查询" aria-label="Permalink to “社交查询”">​</a></h2><div class="command-section"><h3 id="查看他人队伍" tabindex="-1">查看他人队伍 <a class="header-anchor" href="#查看他人队伍" aria-label="Permalink to “查看他人队伍”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>视奸 @用户</span></span></code></pre></div><p>查看指定用户的当前队伍综合力及构成。</p><blockquote><p>需要对方开启「给看」权限</p></blockquote><h3 id="查询歌曲进度" tabindex="-1">查询歌曲进度 <a class="header-anchor" href="#查询歌曲进度" aria-label="Permalink to “查询歌曲进度”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>逮捕</span></span></code></pre></div><p>查询 Expert/Master FC/AP 进度。</p><blockquote><p><strong>需先上传数据</strong></p></blockquote></div><hr><h2 id="数据上传说明" tabindex="-1">数据上传说明 <a class="header-anchor" href="#数据上传说明" aria-label="Permalink to “数据上传说明”">​</a></h2><div class="upload-info"><h3 id="⚠️-数据上传重要说明" tabindex="-1">⚠️ 数据上传重要说明 <a class="header-anchor" href="#⚠️-数据上传重要说明" aria-label="Permalink to “⚠️ 数据上传重要说明”">​</a></h3><p>以下高阶功能（如 <code>rk</code>, <code>b39</code>, <code>进度</code> 等）<strong>必须上传游戏数据</strong>才能使用。</p><h4 id="上传方式" tabindex="-1">上传方式 <a class="header-anchor" href="#上传方式" aria-label="Permalink to “上传方式”">​</a></h4><ol><li><p><strong>访问数据上传页面</strong><a href="http://go.mikuware.top/" target="_blank" rel="noreferrer">👉 点我进入上传页面</a></p></li><li><p><strong>日服玩家特权</strong> 可直接复制游戏内的「引继信息」发送给 Bot 自动完成上传</p><blockquote><p>需注意引继码一次性失效，请谨慎操作或重新引继</p></blockquote></li></ol><h4 id="数据安全" tabindex="-1">数据安全 <a class="header-anchor" href="#数据安全" aria-label="Permalink to “数据安全”">​</a></h4><ul><li>上传的数据仅用于查询功能</li><li>数据存储在加密服务器</li><li>可随时删除上传的数据</li></ul></div><hr><h2 id="指令速查表" tabindex="-1">指令速查表 <a class="header-anchor" href="#指令速查表" aria-label="Permalink to “指令速查表”">​</a></h2><table tabindex="0"><thead><tr><th>指令</th><th>功能</th><th>需要上传数据</th></tr></thead><tbody><tr><td><code>绑定 ID</code></td><td>绑定游戏账号</td><td>❌</td></tr><tr><td><code>给看</code> / <code>不给看</code></td><td>设置查询权限</td><td>❌</td></tr><tr><td><code>pjskprofile</code></td><td>查看个人资料</td><td>❌</td></tr><tr><td><code>视奸</code></td><td>查看他人队伍</td><td>❌</td></tr><tr><td><code>id</code></td><td>查看绑定 ID</td><td>❌</td></tr><tr><td><code>逮捕</code></td><td>查询歌曲进度</td><td>✅</td></tr></tbody></table><hr><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h2><div class="tip custom-block github-alert"><p class="custom-block-title">使用建议</p><p></p><ul><li>绑定后建议设置一个易记的昵称</li><li>定期更新数据以获得准确信息</li><li>保护好自己的游戏 ID 信息</li></ul></div><div class="warning custom-block github-alert"><p class="custom-block-title">隐私提醒</p><p></p><ul><li>「不给看」模式下他人无法查询你的数据</li><li>敏感信息建议私聊 BOT 查询</li><li>谨慎分享个人游戏数据</li></ul></div><hr><div class="nav-footer"><a href="./" class="nav-prev">← 返回 SakuraBOT 专项</a><a href="./advanced" class="nav-next">下一页：高阶数据分析 →</a></div>',21)])])}const b=e(l,[["render",d]]);export{k as __pageData,b as default};
